/**
 * DiceDuel PDA Derivation Functions
 *
 * Standalone PDA derivation functions extracted from the IDL.
 * These complement the auto-resolved PDA defaults in instruction builders.
 * Used by indexer handlers and other code that needs PDA derivation
 * without building instructions.
 *
 * NOTE: This file is NOT auto-generated by Codama (Codama embeds PDA
 * resolution in instruction builders). It is maintained alongside the
 * generated code and uses the same program address constant.
 */

import {
	type Address,
	type ProgramDerivedAddress,
	getAddressEncoder,
	getProgramDerivedAddress,
} from "@solana/kit";
import { DICE_DUEL_PROGRAM_ADDRESS } from "./programs";

const addressEncoder = getAddressEncoder();
const textEncoder = new TextEncoder();

function strSeed(s: string): Uint8Array {
	return textEncoder.encode(s);
}

function addrSeed(addr: Address): Uint8Array {
	return new Uint8Array(addressEncoder.encode(addr));
}

function u8Seed(n: number): Uint8Array {
	return new Uint8Array([n]);
}

function u64Seed(n: bigint): Uint8Array {
	const buf = new Uint8Array(8);
	new DataView(buf.buffer).setBigUint64(0, n, true);
	return buf;
}

function derive(
	seeds: Uint8Array[],
	programId: Address = DICE_DUEL_PROGRAM_ADDRESS,
): Promise<ProgramDerivedAddress> {
	return getProgramDerivedAddress({ seeds, programAddress: programId });
}

/** GameConfig singleton PDA: seeds = ["config"] */
export function findConfigPda() {
	return derive([strSeed("config")]);
}

/** DiceBag PDA: seeds = ["dice_bag", mint] */
export function findDiceBagPda(mint: Address) {
	return derive([strSeed("dice_bag"), addrSeed(mint)]);
}

/** Wager PDA: seeds = ["wager", challenger, nonce_le_bytes] */
export function findWagerPda(challenger: Address, nonce: bigint) {
	return derive([strSeed("wager"), addrSeed(challenger), u64Seed(nonce)]);
}

/** Escrow PDA: seeds = ["escrow", wager] */
export function findEscrowPda(wager: Address) {
	return derive([strSeed("escrow"), addrSeed(wager)]);
}

/** PlayerStats PDA: seeds = ["stats", player] */
export function findStatsPda(player: Address) {
	return derive([strSeed("stats"), addrSeed(player)]);
}

/** GameType PDA: seeds = ["game_type", id (u8)] */
export function findGameTypePda(id: number) {
	return derive([strSeed("game_type"), u8Seed(id)]);
}

/** Program identity PDA for VRF: seeds = ["identity"] */
export function findProgramIdentityPda() {
	return derive([strSeed("identity")]);
}
